CREATE TABLE `cycle` (
  `cycle_id` int NOT NULL AUTO_INCREMENT,
  `cycle_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cycle_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cycle_brand` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `cycle_model` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `purchase_date` date NOT NULL,
  `qr_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `current_status` enum('Available','Rented','Under Maintenance','Damaged','Retired') COLLATE utf8mb4_unicode_ci DEFAULT 'Available',
  `total_rides` int DEFAULT '0',
  `current_station_id` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `current_service_id` int DEFAULT NULL,
  `service_interval_days` int DEFAULT '30',
  `next_service_date` date DEFAULT NULL,
  PRIMARY KEY (`cycle_id`),
  UNIQUE KEY `qr_code` (`qr_code`),
  KEY `idx_cycle_type` (`cycle_type`),
  KEY `idx_current_status` (`current_status`),
  KEY `idx_qr_code` (`qr_code`),
  KEY `idx_station` (`current_station_id`),
  KEY `current_service_id` (`current_service_id`),
  CONSTRAINT `cycle_ibfk_1` FOREIGN KEY (`current_service_id`) REFERENCES `cycle_service` (`service_id`),
  CONSTRAINT `fk_cycle_station` FOREIGN KEY (`current_station_id`) REFERENCES `station` (`station_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `cycle_chk_1` CHECK ((`total_rides` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=222 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
